import './Hero.css'

const Hero = () => {
    return (
        <section className="hero">
            <h1>mWallet – контролюй портфель легко</h1>
            <p>Підключи рахунок та отримай повний контроль над фінансами</p>
            <button>Почати зараз</button>
        </section>
    )
}

export default Hero
